  ('a2222222-0000-4000-8000-000000000001', 'opening', 'a1111111-0000-4000-8000-000000000001', 'C50', 'Partita Italiana — Giuoco Piano', 'italiana-giuoco-piano', 'Bozza da revisione: sviluppo, f7 e centro c3-d4.', '{"intro":"Bozza da revisione. La Partita Italiana (Giuoco Piano): sviluppo naturale e pressione su f7, poi c3-d4 per il centro. La linea arriva fino al mediogioco, così vedi COME si continua dopo le mosse di teoria.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"e4","uci":"e2e4","fen":"rnbqkbnr/pppppppp/8/8/4P3/8/PPPP1PPP/RNBQKBNR b KQkq - 0 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"e5","uci":"e7e5","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/8/PPPP1PPP/RNBQKBNR w KQkq - 0 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"Nf3","uci":"g1f3","fen":"rnbqkbnr/pppp1ppp/8/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R b KQkq - 1 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"Nc6","uci":"b8c6","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/4P3/5N2/PPPP1PPP/RNBQKB1R w KQkq - 2 3","children":["n5"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Bc4","uci":"f1c4","fen":"r1bqkbnr/pppp1ppp/2n5/4p3/2B1P3/5N2/PPPP1PPP/RNBQK2R b KQkq - 3 3","children":["n6","n7","n9"]},"n6":{"id":"n6","parentId":"n5","ply":6,"san":"Bc5","uci":"f8c5","fen":"r1bqk1nr/pppp1ppp/2n5/2b1p3/2B1P3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":["n10"]},"n7":{"id":"n7","parentId":"n5","ply":6,"san":"Nf6","uci":"g8f6","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p3/2B1P3/5N2/PPPP1PPP/RNBQK2R w KQkq - 4 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":7,"san":"Ng5","uci":"f3g5","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p1N1/2B1P3/8/PPPP1PPP/RNBQK2R b KQkq - 5 4","children":[],"comment":"Difesa dei due cavalli, tagliente."},"n9":{"id":"n9","parentId":"n5","ply":6,"san":"Be7","uci":"f8e7","fen":"r1bqk1nr/ppppbppp/2n5/4p3/2B