1 w - - 3 14","children":["n34"]},"n34":{"id":"n34","parentId":"n33","ply":27,"san":"Ne5","uci":"f3e5","fen":"2kr3r/ppp2ppp/2n1b3/3qN3/2pPR3/B1P5/P3QPPP/R5K1 b - - 4 14","children":["n35"]},"n35":{"id":"n35","parentId":"n34","ply":28,"san":"Nxe5","uci":"c6e5","fen":"2kr3r/ppp2ppp/4b3/3qn3/2pPR3/B1P5/P3QPPP/R5K1 w - - 0 15","children":["n36"]},"n36":{"id":"n36","parentId":"n35","ply":29,"san":"Rxe5","uci":"e4e5","fen":"2kr3r/ppp2ppp/4b3/3qR3/2pP4/B1P5/P3QPPP/R5K1 b - - 0 15","children":["n37"]},"n37":{"id":"n37","parentId":"n36","ply":30,"san":"Qd7","uci":"d5d7","fen":"2kr3r/pppq1ppp/4b3/4R3/2pP4/B1P5/P3QPPP/R5K1 w - - 1 16","children":[]}},"rootId":"n0","seq":38},"steps":[{"nodeId":"n5","text":"L''alfiere si punta su f7, la casa più debole del campo nero. È l''idea che dà il nome all''Italiana.","shapes":[{"orig":"c4","dest":"f7","brush":"red"},{"orig":"f7","brush":"red"}],"highlightMoves":["Bc5","Nf6","Be7"]},{"nodeId":"n10","text":"c3 prepara d4: il Bianco vuole un grande centro di pedoni e più spazio.","shapes":[{"orig":"d2","dest":"d4","brush":"green"}]},{"nodeId":"n12","text":"Rotto il centro con d4: si aprono le linee e inizia il vero gioco. Prova a deviare per vedere cosa dice il motore."},{"nodeId":"n16","text":"Cc3 è un gambetto: il Bianco lascia prendere e4 per sviluppare più in fretta. Se il Nero arraffa pedoni e pezzi (vedi la variante 8…Cxc3 9.bxc3 Axc3?), Db3! punisce subito.","shapes":[{"orig":"e4","brush":"red"}]},{"nodeId":"n25","text":"Il contro-colpo d5! è la risorsa difensiva chiave: blocca l''attacco dell''alfiere c4 e apre la diagonale all''alfiere c8. Senza questa mossa il Nero soffocherebbe.","shapes":[{"orig":"d7","dest":"d5","brush":"green"}]},{"nodeId":"n33","text":"Siamo nel mediogioco: il Nero arrocca lungo e la struttura è definita. Il Bianco ha attività sulle colonne centrali e l''alfiere in a3 che taglia la scacchiera; il Nero ha un pedone in più (c4) e gioco sulla colonna d."},{"nodeId":"n37","text":"Posizione tipica di mediogioco dell''Italiana classica: pezzi pesanti attivi per il Bianco contro struttura e pedone in più del Nero. Da qui si gioca coi piani descritti sotto in «Come continuare»."}],"plan":"Col Bianco: tieni i pezzi pesanti attivi sulle colonne centrali (Te1/Te5, Dd2-f4 o De2-e4), punta ai pedoni neri dell''ala di donna (a7, c4) e sfrutta l''alfiere in a3 che impedisce al Re nero di trovare pace. Col Nero: consolida con f6 e Td8-d5, restituisci se serve il pedone c4 per cambiare i pezzi pesanti — ogni cambio avvicina un finale dove il pedone in più conta. In generale: chi ha l''iniziativa evita i cambi, chi ha la struttura migliore li cerca."}'::jsonb, 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1', '1. e4 e5 2. Nf3 Nc6 3. Bc4 Bc5 (3... Nf6 4. Ng5 {Difesa dei due cavalli, tagliente.}) (3... Be7 {più prudente.}) 4. c3 Nf6 5. d4 exd4 6. cxd4 Bb4+ 7. Nc3 Nxe4 8. O-O Bxc3 (8... Nxc3 9. bxc3 Bxc3 {Avidità punita:} 10. Qb3 {con doppio attacco su f7 e sull''alfiere: il Nero crolla.}) 9. bxc3 d5 10. Ba3 dxc4 11. Re1 Be6 12. Rxe4 Qd5 13. Qe2 O-O-O 14. Ne5 Nxe5 15. Rxe5 Qd7', 0, 1, true),
  ('a2222222-0000-4000-8000-000000000002', 'opening', 'a1111111-0000-4000-8000-000000000002', 'B12', 'Caro-Kann — linea principale', 'caro-kann-principale', 'Bozza da revisione: l''alfiere attivo in f5 e la struttura tipica.', '{"intro":"Bozza da revisione. La Caro-Kann: solida e istruttiva. Il Nero apre alla difesa con c6+d5 senza chiudere l''alfiere campochiaro. La linea prosegue fino al mediogioco, con la rottura tematica c5: così vedi il PIANO, non solo le mosse.","tree":{"nodes":{"n0":{"id":"n0","parentId":null,"ply":0,"san":null,"uci":null,"fen":"rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1","children":["n1"]},"n1":{"id":"n1","parentId":"n0","ply":1,"san":"e4","uci":"e2e4","fen":"rnbqkbnr/pppppppp/8/8/4P3/8/PPPP1PPP/RNBQKBNR b KQkq - 0 1","children":["n2"]},"n2":{"id":"n2","parentId":"n1","ply":2,"san":"c6","uci":"c7c6","fen":"rnbqkbnr/pp1ppppp/2p5/8/4P3/8/PPPP1PPP/RNBQKBNR w KQkq - 0 2","children":["n3"]},"n3":{"id":"n3","parentId":"n2","ply":3,"san":"d4","uci":"d2d4","fen":"rnbqkbnr/pp1ppppp/2p5/8/3PP3/8/PPP2PPP/RNBQKBNR b KQkq - 0 2","children":["n4"]},"n4":{"id":"n4","parentId":"n3","ply":4,"san":"d5","uci":"d7d5","fen":"rnbqkbnr/pp2pppp/2p5/3p4/3PP3/8/PPP2PPP/RNBQKBNR w KQkq - 0 3","children":["n5","n6"]},"n5":{"id":"n5","parentId":"n4","ply":5,"san":"Nc3","uci":"b1c3","fen":"rnbqkbnr/pp2pppp/2p5/3p4/3PP3/2N5/PPP2PPP/R1BQKBNR b KQkq - 1 3","children":["n10"]},"n6":{"id":"n6","parentId":"n4","ply":5,"san":"exd5","uci":"e4d5","fen":"rnbqkbnr/pp2pppp/2p5/3P4/3P4/8/PPP2PPP/RNBQKBNR b KQkq - 0 3","children":["n7"]},"n7":{"id":"n7","parentId":"n6","ply":6,"san":"cxd5","uci":"c6d5","fen":"rnbqkbnr/pp2pppp/8/3p4/3P4/8/PPP2PPP/RNBQKBNR w KQkq - 0 4","children":["n8"]},"n8":{"id":"n8","parentId":"n7","ply":7,"san":"Bd3","uci":"f1d3","fen":"rnbqkbnr/pp2pppp/8/3p4/3P4/3B4/PPP2PPP/RNBQK1NR b KQkq - 1 4","children":["n9"]},"n9":{"id":"n9","parentId":"n8","ply":8,"san":"Nc6","uci":"b8c6","fen":"r1bqkbnr/pp2pppp/2n5/3p4/3P4/3B4/PPP2PPP/RNBQK1NR w KQkq - 2 5",